#include <stdio.h>
#include <stdint.h>

static uint64_t gcd_uint64(uint64_t a, uint64_t b) {
    while (b) {
        uint64_t t = a % b;
        a = b;
        b = t;
    }
    return a;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        uint64_t A, B;
        scanf("%llu %llu", (unsigned long long*)&A, (unsigned long long*)&B);
        if (A < 2 || B < 2) {
            printf("-1\n");
            continue;
        }
        uint64_t g = gcd_uint64(A, B);
        if (g >= 2) printf("0\n");
        else printf("1\n");
    }
    return 0;
}

