#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        A = int(next(it)); B = int(next(it))
        if A < 2 or B < 2:
            out.append('-1')
            continue
        g = math.gcd(A, B)
        out.append('0' if g >= 2 else '1')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

